---@class StructHeroOutfitShow
local StructHeroOutfitShow = LxClass("StructHeroOutfitShow", nil)
function StructHeroOutfitShow:StructHeroOutfitShow()
	self.hero = nil
	self.outfits = {}
	self.wearOutfitList = {}
end

function StructHeroOutfitShow:CreateByPb(pb)
	local hero = StructHero:New()
	hero:CreateByPb(pb.hero)
	self.hero = hero:GetServerData()

	local outfitList = {}
	for i,v in ipairs(pb.outfits) do
		local position = v.position
		local outfit = StructOutfit:New()
		outfit:CreateByPb(v.outfit)
		outfitList[position] = outfit
	end

	self.outfits = {}

	for i = 1,4 do
		local outfitServerData = outfitList[i]
		local isHave = true
		if not outfitServerData then
			isHave = false
			outfitServerData = {}
		elseif type(outfitServerData) ~= "table" then
			isHave = false
			outfitServerData = {}
		end
		local data = {}
		data.isHave = isHave
		data.refId = i
		data.position = i
		data.outfit = outfitServerData
		table.insert(self.outfits,data)
	end

	self.wearOutfitList = outfitList
end

return StructHeroOutfitShow